(function () {
    'use strict';

    const TH = window.TavernHelper;
    if (!TH) {
        console.warn('[MVU 样例] 未检测到 JS-Slash-Runner / TavernHelper');
        return;
    }

    function notify(msg, level = 'info') {
        if (window.toastr && typeof window.toastr[level] === 'function') {
            window.toastr[level](msg, 'MVU 样例');
        } else {
            console.log(`[MVU 样例][${level}]`, msg);
        }
    }

    async function main() {
        // 等待 MVU 初始化
        await waitGlobalInitialized('Mvu');

        // 1. 命令解析后清理路径
        eventOn(Mvu.events.COMMAND_PARSED, commands => {
            commands.forEach(c => {
                c.args[0] = c.args[0].replaceAll('-', '');
            });
        });

        // 2. 数值范围限制
        eventOn(Mvu.events.VARIABLE_UPDATE_ENDED, (next, prev) => {
            _.update(next, 'stat_data.白娅.依存度', v => _.clamp(v, 0, 100));
        });

        // 3. 限制单轮变化幅度
        eventOn(Mvu.events.VARIABLE_UPDATE_ENDED, (next, prev) => {
            const old = _.get(prev, 'stat_data.白娅.依存度');
            if (typeof old === 'number') {
                _.update(next, 'stat_data.白娅.依存度', v => _.clamp(v, old - 3, old + 3));
            }
        });

        // 4. 注入阶段提示词激活绿灯
        eventOn(Mvu.events.VARIABLE_UPDATE_ENDED, vars => {
            const value = _.get(vars, 'stat_data.白娅.依存度');
            let stage = '一';
            if (typeof value === 'number') {
                if (value >= 80) stage = '五';
                else if (value >= 60) stage = '四';
                else if (value >= 40) stage = '三';
                else if (value >= 20) stage = '二';
            }
            injectPrompts([{
                id: '激活-白娅阶段',
                content: `白娅阶段${stage}`,
                position: 'none',
                depth: 0,
                role: 'user',
                should_scan: true,
            }]);
        });

        notify('MVU 样例脚本已就绪', 'success');
    }

    main().catch(error => {
        console.error('[MVU 样例] 初始化失败', error);
        notify(error.message || String(error), 'error');
    });
})();
